final:
module RefModule(
    input data_in_0,
    input data_in_1,
    input enable,
    output reg data_out
);
  wire _tap_data_in_0 = data_in_0 & {1{1'b1}};


always @(*) begin
    if(enable == 1'b0) begin
        data_out = data_in_0;
    end
    else begin
        data_out = data_in_1;
    end
end

endmodule
